import java.io.*;
import java.util.*;

public class Main {
    private static long squareArea(int a) {
        return (long) a * a;
    }
    private static long cubeSurface(int b) {
        return 6L * b * b;
    }
    private static double circleArea(double r) {
        return Math.PI * r * r;
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder sb = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for (int t = 0; t < T; t++) {
            String line = br.readLine();
            while (line != null && line.trim().isEmpty()) {
                line = br.readLine();
            }
            StringTokenizer st = new StringTokenizer(line);
            int a = Integer.parseInt(st.nextToken());
            int b = Integer.parseInt(st.nextToken());
            double r = Double.parseDouble(st.nextToken());
            sb.append(squareArea(a)).append('\n');
            sb.append(cubeSurface(b)).append('\n');
            sb.append(String.format(java.util.Locale.US, "%.5f", circleArea(r))).append('\n');
        }
        System.out.print(sb.toString());
    }
}

